/*
 * M14 — Decompose table (approximate; text-safe).
 *
 * Turns the selected table into a grid of text boxes (one per cell), placed to
 * the RIGHT of the original — the table itself is left untouched.
 *
 * Fidelity notes (Office.js limits):
 *   - No per-cell geometry is exposed. On PowerPointApi 1.9+ we read real column
 *     widths (TableColumn.width) and row heights (TableRow.height) for a
 *     proportional layout; otherwise we divide the table's box equally.
 *   - Merged cells: getCellOrNullObject returns a null object for covered cells
 *     (skipped); the anchor cell carries rowCount/columnCount, so its box spans.
 *   - Cell fill/font/borders are NOT copied — text + position/size only.
 */

/* global PowerPoint */

import { isSupported } from "./capabilities";

export interface DecomposeResult {
  boxes: number;
  problem?: string;
  note?: string;
}

/** Cumulative, scaled edge offsets (length count+1) so the grid fills `total`. */
function buildOffsets(sizes: number[] | null, count: number, total: number): number[] {
  const offsets = [0];
  if (sizes && sizes.length === count) {
    const sum = sizes.reduce((a, b) => a + b, 0) || 1;
    const scale = total / sum;
    for (let i = 0; i < count; i++) {
      offsets.push(offsets[i] + sizes[i] * scale);
    }
  } else {
    const each = total / count;
    for (let i = 0; i < count; i++) {
      offsets.push(offsets[i] + each);
    }
  }
  return offsets;
}

export async function decomposeTable(referenceId: string | null): Promise<DecomposeResult> {
  if (!referenceId) {
    return { boxes: 0, problem: "Select a table to decompose first." };
  }
  const useGeom = isSupported("tableGeom");

  return PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type,items/left,items/top,items/width,items/height");
    await context.sync();

    const shape =
      selected.items.find((s) => s.id === referenceId) || selected.items[selected.items.length - 1];
    if (!shape) {
      return { boxes: 0, problem: "Select a table to decompose first." };
    }
    if ((shape.type as unknown as string) !== "Table") {
      return { boxes: 0, problem: "That isn't a table — select a table shape to decompose." };
    }
    const tableLeft = shape.left;
    const tableTop = shape.top;
    const tableWidth = shape.width;
    const tableHeight = shape.height;

    const table = shape.getTable();
    table.load("rowCount,columnCount");
    const columns = useGeom ? table.columns : null;
    const rows = useGeom ? table.rows : null;
    if (columns) {
      columns.load("items/width");
    }
    if (rows) {
      rows.load("items/height");
    }
    await context.sync();

    const rowCount = table.rowCount;
    const colCount = table.columnCount;
    if (rowCount < 1 || colCount < 1) {
      return { boxes: 0, problem: "That table has no cells." };
    }

    const colWidths = columns ? columns.items.map((c) => c.width) : null;
    const rowHeights = rows ? rows.items.map((r) => r.height) : null;
    const colOff = buildOffsets(colWidths, colCount, tableWidth);
    const rowOff = buildOffsets(rowHeights, rowCount, tableHeight);

    // Read every cell (null objects mark merged-away cells).
    const cells: PowerPoint.TableCell[] = [];
    for (let r = 0; r < rowCount; r++) {
      for (let c = 0; c < colCount; c++) {
        const cell = table.getCellOrNullObject(r, c);
        // isNullObject is the intended *OrNullObject signal (merged-away cells).
        // eslint-disable-next-line office-addins/no-navigational-load
        cell.load("isNullObject,text,rowIndex,columnIndex,rowCount,columnCount");
        if (useGeom) {
          // Cell fill + font (PowerPointApi 1.9) so the boxes keep the table's look.
          cell.fill.load("type,foregroundColor");
          cell.font.load("name,size,bold,italic,color");
        }
        cells.push(cell);
      }
    }
    await context.sync();

    const baseX = tableLeft + tableWidth + 12; // place the grid beside the table
    let boxes = 0;
    for (const cell of cells) {
      if (cell.isNullObject) {
        continue;
      }
      const ci = cell.columnIndex;
      const ri = cell.rowIndex;
      const left = baseX + colOff[ci];
      const top = tableTop + rowOff[ri];
      const width = colOff[Math.min(ci + cell.columnCount, colCount)] - colOff[ci];
      const height = rowOff[Math.min(ri + cell.rowCount, rowCount)] - rowOff[ri];

      const box = slide.shapes.addTextBox(cell.text || "", {
        left,
        top,
        width: Math.max(width, 1),
        height: Math.max(height, 1),
      });
      // Light border so the result still reads as a grid.
      box.lineFormat.visible = true;
      box.lineFormat.color = "#B0B4BB";
      box.lineFormat.weight = 0.75;

      if (useGeom) {
        // Copy the cell's fill + font so the grid keeps the table's look.
        const fillType = cell.fill.type as unknown as string;
        if (fillType === "Solid") {
          box.fill.setSolidColor(cell.fill.foregroundColor);
        } else if (fillType === "NoFill") {
          box.fill.clear();
        }
        const bf = box.textFrame.textRange.font;
        const cf = cell.font;
        if (cf.name) {
          bf.name = cf.name;
        }
        if (typeof cf.size === "number") {
          bf.size = cf.size;
        }
        if (cf.bold !== null) {
          bf.bold = cf.bold;
        }
        if (cf.italic !== null) {
          bf.italic = cf.italic;
        }
        if (cf.color) {
          bf.color = cf.color;
        }
      }
      boxes++;
    }
    await context.sync();

    return {
      boxes,
      note: useGeom
        ? "Column widths, row heights, merged cells, cell fill & font preserved; borders approximated."
        : "Equal sizes, no cell colors (this build can't read table geometry); merged cells preserved.",
    };
  });
}
