/*
 * Writes engine output back to the live selection.
 *
 * The engine returns full ShapeProps; this adapter re-fetches the current
 * selection and writes geometry onto the shapes whose ids match. Matching by id
 * (rather than trusting a stale handle) keeps writes correct even if the
 * selection shifted, and naturally scopes changes to what's actually selected.
 *
 * Position and size are set from the passed shapes; callers that only want to
 * move shapes simply pass the original width/height back unchanged (a no-op).
 */

/* global PowerPoint */

import { ShapeProps } from "../core";

export async function applyShapes(shapes: ReadonlyArray<ShapeProps>): Promise<void> {
  if (shapes.length === 0) {
    return;
  }
  const byId = new Map(shapes.map((s) => [s.id, s]));

  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id");
    await context.sync();

    for (const shape of selected.items) {
      const target = byId.get(shape.id);
      if (!target) {
        continue;
      }
      shape.left = target.left;
      shape.top = target.top;
      shape.width = target.width;
      shape.height = target.height;
    }
    await context.sync();
  });
}
