/*
 * M12 — Color eyedropper (no screen sampling / EyeDropper API).
 *
 * Pick a color from the selected shape (cached in the pane), then apply it to
 * whatever you select next. `readMasterColor` reads the fill or line color of
 * the reference shape; `applyFillColor` / `applyLineColor` paint the selection.
 *
 * Reads/writes are guarded by shape type — loading fill/lineFormat on a shape
 * that lacks them (group, picture, chart) throws.
 */

/* global PowerPoint */

const FILL_TYPES = new Set(["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"]);
const LINE_TYPES = new Set([
  "GeometricShape",
  "TextBox",
  "Placeholder",
  "Callout",
  "Freeform",
  "Line",
]);

export type ColorKind = "fill" | "line";

export interface PickResult {
  color?: string;
  problem?: string;
}

/** Reads the fill or line color of the reference (source) shape. */
export async function readMasterColor(
  referenceId: string | null,
  kind: ColorKind
): Promise<PickResult> {
  if (!referenceId) {
    return { problem: "Select the shape to pick a color from first." };
  }
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();

    const source =
      selected.items.find((s) => s.id === referenceId) || selected.items[selected.items.length - 1];
    if (!source) {
      return { problem: "Select the shape to pick a color from first." };
    }
    const type = source.type as unknown as string;

    if (kind === "fill") {
      if (!FILL_TYPES.has(type)) {
        return { problem: "That shape has no fill to pick." };
      }
      source.fill.load("type,foregroundColor");
      await context.sync();
      if ((source.fill.type as unknown as string) !== "Solid") {
        return { problem: "That shape's fill isn't a solid color." };
      }
      return { color: source.fill.foregroundColor };
    }

    if (!LINE_TYPES.has(type)) {
      return { problem: "That shape has no line to pick." };
    }
    source.lineFormat.load("color");
    await context.sync();
    return { color: source.lineFormat.color };
  });
}

/** Apply a solid fill color to every fill-capable selected shape. */
export async function applyFillColor(hex: string): Promise<number> {
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();
    let count = 0;
    for (const s of selected.items) {
      if (FILL_TYPES.has(s.type as unknown as string)) {
        s.fill.setSolidColor(hex);
        count++;
      }
    }
    await context.sync();
    return count;
  });
}

/** Apply a line color to every line-capable selected shape. */
export async function applyLineColor(hex: string): Promise<number> {
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();
    let count = 0;
    for (const s of selected.items) {
      if (LINE_TYPES.has(s.type as unknown as string)) {
        s.lineFormat.color = hex;
        s.lineFormat.visible = true;
        count++;
      }
    }
    await context.sync();
    return count;
  });
}
