/*
 * M3 — Distribute (equal edge-to-edge spacing).
 *
 * Both "distribute across the selection" and "distribute across the slide"
 * reduce to spreading shapes evenly along a 1-D span [start, end]:
 *
 *   gap = (span - sum-of-sizes) / (n - 1)
 *
 * then lay the shapes out left→right (or top→bottom) with that constant gap.
 *
 *  - Across the SELECTION, span = [leftmost edge, rightmost edge], so the two
 *    outermost shapes don't move and the inner ones get evenly spaced — the
 *    PowerPoint-standard behavior.
 *  - Across the SLIDE, span = [0, slideWidth/Height], so the whole selection is
 *    spread to fill the slide (outermost shapes snap to the slide edges).
 *
 * Needs at least 3 shapes to be meaningful; fewer returns unchanged copies.
 * Gaps may go negative if the shapes are wider than the span (they'll overlap
 * evenly) — that's the correct, predictable result.
 */

import { ShapeProps, SlideSize } from "./types";

export type DistributeAxis = "horizontal" | "vertical";

function distributeAlong(
  shapes: ReadonlyArray<ShapeProps>,
  axis: DistributeAxis,
  spanStart: number,
  spanEnd: number
): ShapeProps[] {
  if (shapes.length < 3) {
    return shapes.map((s) => ({ ...s }));
  }
  const horizontal = axis === "horizontal";
  const pos = (s: ShapeProps) => (horizontal ? s.left : s.top);
  const size = (s: ShapeProps) => (horizontal ? s.width : s.height);

  const sorted = [...shapes].sort((a, b) => pos(a) - pos(b));
  const sumSizes = sorted.reduce((acc, s) => acc + size(s), 0);
  const gap = (spanEnd - spanStart - sumSizes) / (sorted.length - 1);

  const newPos = new Map<string, number>();
  let cursor = spanStart;
  for (const s of sorted) {
    newPos.set(s.id, cursor);
    cursor += size(s) + gap;
  }

  // Return in original order; only the axis coordinate changes.
  return shapes.map((s) => {
    const p = newPos.get(s.id) as number;
    return horizontal ? { ...s, left: p } : { ...s, top: p };
  });
}

/** Even spacing within the selection; the two outermost shapes stay put. */
export function distributeAcrossSelection(
  shapes: ReadonlyArray<ShapeProps>,
  axis: DistributeAxis
): ShapeProps[] {
  if (shapes.length < 3) {
    return shapes.map((s) => ({ ...s }));
  }
  const horizontal = axis === "horizontal";
  const start = Math.min(...shapes.map((s) => (horizontal ? s.left : s.top)));
  const end = Math.max(...shapes.map((s) => (horizontal ? s.left + s.width : s.top + s.height)));
  return distributeAlong(shapes, axis, start, end);
}

/** Even spacing across the whole slide; outermost shapes snap to the slide edges. */
export function distributeAcrossSlide(
  shapes: ReadonlyArray<ShapeProps>,
  axis: DistributeAxis,
  slide: SlideSize
): ShapeProps[] {
  const end = axis === "horizontal" ? slide.width : slide.height;
  return distributeAlong(shapes, axis, 0, end);
}
