/*
 * M7 — Text box merge / split (office adapter).
 *
 * MERGE: concatenate the selected text boxes (reading order) into the reference
 * box, delete the rest. Setting plain text means per-run formatting of the
 * merged-in text is NOT preserved — the caller warns about this.
 *
 * SPLIT: break the reference text box into stacked boxes, one per paragraph (or
 * per line), sharing the source's left/width and base font. Split-at-cursor is
 * not supported (no caret API).
 */

/* global PowerPoint */

import { readingOrder, SplitMode, splitText } from "../core";

/** Shape types that can hold text. */
const TEXT_TYPES = new Set(["TextBox", "GeometricShape", "Placeholder", "Callout", "Freeform"]);

export interface MergeResult {
  merged: boolean;
  count: number;
}

export interface SplitResult {
  /** 0 = no usable target, 1 = nothing to split, >1 = number of boxes created. */
  count: number;
}

export async function mergeTextBoxes(referenceId: string | null): Promise<MergeResult> {
  return PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type,items/left,items/top");
    await context.sync();

    const candidates = selected.items.filter((s) => TEXT_TYPES.has(s.type as unknown as string));
    for (const s of candidates) {
      s.textFrame.load("hasText");
      s.textFrame.textRange.load("text");
    }
    await context.sync();

    const withText = candidates.filter((s) => s.textFrame.hasText);
    if (withText.length < 2) {
      return { merged: false, count: 0 };
    }

    const ordered = readingOrder(withText);
    const combined = ordered.map((s) => s.textFrame.textRange.text).join("\n");

    // Target = the reference box if it's one of the text boxes, else the first.
    const target = withText.find((s) => s.id === referenceId) || ordered[0];
    target.textFrame.textRange.text = combined;

    for (const s of withText) {
      if (s.id !== target.id) {
        s.delete();
      }
    }
    await context.sync();

    slide.setSelectedShapes([target.id]);
    await context.sync();

    return { merged: true, count: withText.length };
  });
}

export async function splitTextBox(
  referenceId: string | null,
  mode: SplitMode
): Promise<SplitResult> {
  return PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type,items/left,items/top,items/width,items/height");
    await context.sync();

    const candidates = selected.items.filter((s) => TEXT_TYPES.has(s.type as unknown as string));
    // Prefer the reference; otherwise only proceed if there's exactly one text shape.
    const target =
      candidates.find((s) => s.id === referenceId) ||
      (candidates.length === 1 ? candidates[0] : null);
    if (!target) {
      return { count: 0 };
    }

    target.textFrame.load("hasText");
    target.textFrame.textRange.load("text");
    target.textFrame.textRange.font.load("name,size,bold,italic,color");
    await context.sync();

    if (!target.textFrame.hasText) {
      return { count: 0 };
    }
    const pieces = splitText(target.textFrame.textRange.text, mode);
    if (pieces.length <= 1) {
      return { count: 1 };
    }

    const font = target.textFrame.textRange.font;
    const left = target.left;
    const top = target.top;
    const width = target.width;
    const pieceHeight = target.height / pieces.length;

    const created = pieces.map((piece, i) => {
      const box = slide.shapes.addTextBox(piece, {
        left,
        top: top + i * pieceHeight,
        width,
        height: pieceHeight,
      });
      const f = box.textFrame.textRange.font;
      if (font.name) {
        f.name = font.name;
      }
      if (typeof font.size === "number") {
        f.size = font.size;
      }
      if (font.bold !== null) {
        f.bold = font.bold;
      }
      if (font.italic !== null) {
        f.italic = font.italic;
      }
      if (font.color) {
        f.color = font.color;
      }
      box.load("id");
      return box;
    });

    target.delete();
    await context.sync();

    slide.setSelectedShapes(created.map((b) => b.id));
    await context.sync();

    return { count: pieces.length };
  });
}
