/*
 * M8 — Hide / Unhide (fragile by design).
 *
 * PowerPoint shapes have no "visible" property, so we fake hiding: stash the
 * shape's original left/top in its tags, flag it HIDDEN, and shove it far off
 * the canvas (left = -10000). Unhide reads the tags back, restores the position,
 * and removes the tags.
 *
 * Hidden shapes still exist — they're reachable via PowerPoint's Selection Pane
 * (the UI says so). "Unhide all on this slide" is the reliable escape hatch,
 * since an off-canvas shape is hard to click.
 */

/* global PowerPoint */

import { isSupported } from "./capabilities";
import { UnsupportedError } from "./selection";

const OFFSCREEN_LEFT = -10000;
/** Tag keys (case-insensitive in PowerPoint; kept uppercase to match how they're stored). */
const HIDDEN = "STHIDDEN";
const ORIG_LEFT = "STLEFT";
const ORIG_TOP = "STTOP";

function ensureTagsSupported(): void {
  if (!isSupported("tags")) {
    throw new UnsupportedError("hide/unhide shapes (needs shape tags)");
  }
}

/** Hides the selected shapes; returns how many were newly hidden (skips already-hidden). */
export async function hideShapes(): Promise<number> {
  ensureTagsSupported();
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/left,items/top");
    await context.sync();

    const shapes = selected.items;
    const flags = shapes.map((s) => s.tags.getItemOrNullObject(HIDDEN));
    flags.forEach((f) => f.load("isNullObject"));
    await context.sync();

    let count = 0;
    shapes.forEach((s, i) => {
      if (!flags[i].isNullObject) {
        return; // already hidden — don't overwrite the stored position
      }
      s.tags.add(HIDDEN, "1");
      s.tags.add(ORIG_LEFT, String(s.left));
      s.tags.add(ORIG_TOP, String(s.top));
      s.left = OFFSCREEN_LEFT;
      count++;
    });
    await context.sync();
    return count;
  });
}

/** Unhides every hidden shape on the active slide. */
export async function unhideAllOnSlide(): Promise<number> {
  ensureTagsSupported();
  return PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    /* eslint-disable office-addins/load-object-before-read, office-addins/call-sync-before-read --
       .shapes is a navigation property; it's loaded below before its items are read. */
    const allShapes = slide.shapes;
    allShapes.load("items/id");
    await context.sync();
    const items = allShapes.items;
    /* eslint-enable office-addins/load-object-before-read, office-addins/call-sync-before-read */
    return restoreHidden(context, items);
  });
}

/** Restores position + clears tags for every shape carrying the HIDDEN flag. */
async function restoreHidden(
  context: PowerPoint.RequestContext,
  shapes: PowerPoint.Shape[]
): Promise<number> {
  const entries = shapes.map((s) => ({
    s,
    hidden: s.tags.getItemOrNullObject(HIDDEN),
    left: s.tags.getItemOrNullObject(ORIG_LEFT),
    top: s.tags.getItemOrNullObject(ORIG_TOP),
  }));
  entries.forEach((e) => {
    e.hidden.load("isNullObject");
    e.left.load("isNullObject,value");
    e.top.load("isNullObject,value");
  });
  await context.sync();

  let count = 0;
  for (const e of entries) {
    if (e.hidden.isNullObject) {
      continue;
    }
    if (!e.left.isNullObject) {
      e.s.left = Number(e.left.value);
    }
    if (!e.top.isNullObject) {
      e.s.top = Number(e.top.value);
    }
    e.s.tags.delete(HIDDEN);
    e.s.tags.delete(ORIG_LEFT);
    e.s.tags.delete(ORIG_TOP);
    count++;
  }
  await context.sync();
  return count;
}
