/*
 * M5 — Swap the positions of exactly two shapes.
 *
 * Each shape takes the other's top-left position. Optionally also swap size
 * (width/height), so the two fully exchange bounding boxes. Everything else
 * (fill, line, font, rotation) stays with its original shape.
 *
 * NOTE: z-order swapping is deliberately NOT attempted — that API is preview-only.
 */

import { ShapeProps } from "./types";

/**
 * Given exactly two shapes, returns them with positions swapped (and sizes too
 * if `alsoSwapSize`). If not exactly two, returns unchanged copies so callers
 * fail safe; the UI is responsible for enforcing the "exactly 2" rule.
 */
export function swapTwo(shapes: ReadonlyArray<ShapeProps>, alsoSwapSize: boolean): ShapeProps[] {
  if (shapes.length !== 2) {
    return shapes.map((s) => ({ ...s }));
  }
  const [a, b] = shapes;
  const newA: ShapeProps = { ...a, left: b.left, top: b.top };
  const newB: ShapeProps = { ...b, left: a.left, top: a.top };
  if (alsoSwapSize) {
    newA.width = b.width;
    newA.height = b.height;
    newB.width = a.width;
    newB.height = a.height;
  }
  return [newA, newB];
}
