/*
 * M1 — Align.
 *
 * Pure engine. Every alignment (to a reference shape OR to the slide) reduces to
 * the same operation: move each shape so a chosen edge/center lines up with an
 * "anchor" rectangle. A reference shape IS an anchor; the slide IS an anchor
 * ({0,0,width,height}). So there's a single code path and no special-casing.
 *
 * Aligning the reference shape to itself is a no-op by construction (e.g.
 * left → anchor.left, which already equals the reference's own left), so callers
 * can safely pass the whole selection including the reference.
 */

import { Bounds, ShapeProps, SlideSize } from "./types";
import { bottom, centerX, centerY, right } from "./geometry";

export type AlignEdge = "left" | "right" | "hcenter" | "top" | "bottom" | "vcenter";

/** True for edges that move a shape horizontally (change left), false for vertical. */
export function isHorizontal(edge: AlignEdge): boolean {
  return edge === "left" || edge === "right" || edge === "hcenter";
}

/** The anchor rectangle for a reference shape. */
export function referenceAnchor(reference: ShapeProps): Bounds {
  return {
    left: reference.left,
    top: reference.top,
    width: reference.width,
    height: reference.height,
  };
}

/** The anchor rectangle for the whole slide. */
export function slideAnchor(slide: SlideSize): Bounds {
  return { left: 0, top: 0, width: slide.width, height: slide.height };
}

/** Target left (horizontal edges) or top (vertical edges) for one shape vs. anchor. */
function alignedPosition(shape: ShapeProps, edge: AlignEdge, anchor: Bounds): Partial<ShapeProps> {
  switch (edge) {
    case "left":
      return { left: anchor.left };
    case "right":
      return { left: right(anchor) - shape.width };
    case "hcenter":
      return { left: centerX(anchor) - shape.width / 2 };
    case "top":
      return { top: anchor.top };
    case "bottom":
      return { top: bottom(anchor) - shape.height };
    case "vcenter":
      return { top: centerY(anchor) - shape.height / 2 };
    default:
      return {};
  }
}

/**
 * Returns a new array where each shape has been moved to align to `anchor` along
 * `edge`. Inputs are not mutated. Only left OR top changes; size is untouched.
 */
export function alignToAnchor(
  shapes: ReadonlyArray<ShapeProps>,
  edge: AlignEdge,
  anchor: Bounds
): ShapeProps[] {
  return shapes.map((s) => ({ ...s, ...alignedPosition(s, edge, anchor) }));
}
