/*
 * Task pane controller (UI layer).
 *
 * Thin by design: wire DOM events, call the office adapter, render results.
 * Geometry math lives in ../core; Office.js plumbing in ../office.
 *
 * The UI is an icon grid. Each tool button carries `data-action` (an id in the
 * ACTIONS registry), `data-tip` (name) and `data-desc` (hover explanation).
 * Clicks and hovers are handled by delegation; keyboard shortcuts can be bound
 * to any action (persisted in localStorage) and fire while the pane has focus.
 */

/* global Office, document, window, localStorage, HTMLElement, HTMLButtonElement, HTMLInputElement, KeyboardEvent, MouseEvent */

import {
  AlignEdge,
  alignToAnchor,
  Bounds,
  CopyDirection,
  DistributeAxis,
  distributeAcrossSelection,
  distributeAcrossSlide,
  DockEdge,
  dockToReference,
  dockToSlide,
  FitMode,
  fitToSlide,
  referenceAnchor,
  ScaleDimension,
  scaleSelection,
  setAbsoluteSize,
  ShapeProps,
  SizeMode,
  sizeToReference,
  slideAnchor,
  SplitMode,
  swapTwo,
} from "../core";
import {
  addSelectionChangedHandler,
  applyFillColor,
  applyLineColor,
  applyShapes,
  applyFormat,
  AutoSizeMode,
  captureElement,
  CapturedElement,
  ColorKind,
  copyShapesTo,
  decomposeTable,
  pasteToSelectedSlides,
  readFormat,
  readMasterColor,
  ShapeFormat,
  getSlideSize,
  hideShapes,
  setAutoSize,
  shrinkFontToFit,
  insertSpikeTestShapes,
  isSupported,
  mergeTextBoxes,
  platform,
  readSelectedShapes,
  scaleTypography,
  selectSimilar,
  splitTextBox,
  unhideAllOnSlide,
  UnsupportedError,
} from "../office";

/** Selection last read from PowerPoint, in the API's returned order. */
let currentSelection: ShapeProps[] = [];
/** Id of the reference/master shape (last selected, or a manual override). */
let referenceId: string | null = null;
/** Ids from the previous selection snapshot, used to detect the newest addition. */
let previousSelectionIds: string[] = [];
/** Shared anchor for relative ops: the reference shape or the slide. */
type RelativeTarget = "reference" | "slide";
let relativeTarget: RelativeTarget = "slide";
/** M6 resize dimension, set by the scale actions. */
let scaleDimension: ScaleDimension = "both";

/** Exposed for later reuse: which shape is the measurement reference? */
export function getReferenceShape(): ShapeProps | null {
  return currentSelection.find((s) => s.id === referenceId) ?? null;
}

/* ---------- action registry: id → handler ---------- */

const ACTIONS: Record<string, () => void | Promise<void>> = {
  "align.left": () => onAlign("left"),
  "align.hcenter": () => onAlign("hcenter"),
  "align.right": () => onAlign("right"),
  "align.top": () => onAlign("top"),
  "align.vcenter": () => onAlign("vcenter"),
  "align.bottom": () => onAlign("bottom"),
  "dock.left": () => onDock("left"),
  "dock.right": () => onDock("right"),
  "dock.top": () => onDock("top"),
  "dock.bottom": () => onDock("bottom"),
  "dist.h": () => onDistribute("horizontal"),
  "dist.v": () => onDistribute("vertical"),
  "size.width": () => onSize("width"),
  "size.height": () => onSize("height"),
  "size.both": () => onSize("both"),
  swap: () => onSwap(),
  "resize.both": () => runScale("both"),
  "resize.width": () => runScale("width"),
  "resize.height": () => runScale("height"),
  "resize.absolute": () => onAbsolute(),
  "resize.fit": () => onFit("fit"),
  "resize.fill": () => onFit("fill"),
  "copy.above": () => onCopyTo("above"),
  "copy.below": () => onCopyTo("below"),
  "copy.left": () => onCopyTo("left"),
  "copy.right": () => onCopyTo("right"),
  "text.merge": () => onMerge(),
  "text.splitPara": () => onSplit("paragraph"),
  "text.splitLine": () => onSplit("line"),
  "textfit.shapeToText": () => onTextFit("shapeToText"),
  "textfit.textToShape": () => onShrinkFont(),
  "textfit.off": () => onTextFit("none"),
  "color.pickFill": () => onPick("fill"),
  "color.pickLine": () => onPick("line"),
  "format.copy": () => onCopyFormat(),
  "paste.copy": () => onCaptureElement(),
  "paste.toSlides": () => onPasteToSlides(),
  "table.decompose": () => onDecompose(),
  hide: () => onHide(),
  unhideAll: () => onUnhideAll(),
  similar: () => onSelectSimilar(),
  insertTest: () => onInsertTestShapes(),
};

/** Painter: which mode is armed (color eyedropper or format painter) + caches. */
let pickerArmed: ColorKind | "format" | null = null;
let cachedColor: string | null = null;
let cachedFormat: ShapeFormat | null = null;
/** Element captured for "paste to slides". */
let cachedElement: CapturedElement | null = null;

function runScale(dim: ScaleDimension): Promise<void> {
  scaleDimension = dim;
  return onScale();
}

/* ---------- startup ---------- */

Office.onReady((info) => {
  if (info.host !== Office.HostType.PowerPoint) {
    return;
  }
  el("sideload-msg").hidden = true;
  el("app-body").hidden = false;
  el("platform-badge").textContent = platform();

  // One click handler for every tool button (icon grid + wide buttons).
  document.body.addEventListener("click", onBodyClick);
  // Hover tooltips.
  document.body.addEventListener("mouseover", onBodyOver);
  document.body.addEventListener("mouseout", hideTip);

  // Relative-to override toggle (auto-set on selection change, still clickable).
  document.querySelectorAll(".toggle-btn").forEach((btn) => {
    btn.addEventListener("click", () =>
      setTarget((btn as HTMLElement).dataset.target as RelativeTarget)
    );
  });

  // Shortcuts.
  loadShortcuts();
  el("btn-shortcuts").addEventListener("click", toggleAssignMode);
  document.addEventListener("keydown", onKeyDown);

  updateHints();

  if (!isSupported("selectedShapes")) {
    setStatus(
      "This PowerPoint is too old to read the selection (needs PowerPointApi 1.5). Try a newer build.",
      "error"
    );
    document.querySelectorAll(".ibtn").forEach((b) => ((b as HTMLButtonElement).disabled = true));
    return;
  }

  // Track the live selection so there's no manual "read" step. The eyedropper,
  // when armed, paints the newly selected shapes on each change.
  guard(async () => {
    await addSelectionChangedHandler(() => guard(onSelectionChanged));
    await refreshSelection();
  });
});

/* ---------- delegated click + tooltip ---------- */

function onBodyClick(e: MouseEvent): void {
  const btn = (e.target as HTMLElement).closest(".ibtn") as HTMLElement | null;
  if (!btn || !btn.dataset.action) {
    return;
  }
  const id = btn.dataset.action;
  if (assignMode) {
    startRecording(id, btn);
    return;
  }
  // Any tool other than the painters stops the armed picker (keeps it scoped).
  if (pickerArmed && id !== "color.pickFill" && id !== "color.pickLine" && id !== "format.copy") {
    disarmPicker();
  }
  const run = ACTIONS[id];
  if (run) {
    guard(async () => {
      await run();
    });
  }
}

function onBodyOver(e: MouseEvent): void {
  const node = (e.target as HTMLElement).closest("[data-tip]") as HTMLElement | null;
  if (node) {
    showTip(node);
  }
}

/* ---------- selection tracking ---------- */

async function onInsertTestShapes(): Promise<void> {
  await insertSpikeTestShapes();
  await refreshSelection();
  setStatus("Inserted test shapes A–D.", "ok");
}

async function refreshSelection(): Promise<void> {
  const next = await readSelectedShapes();
  referenceId = pickReferenceId(next, previousSelectionIds, referenceId);
  previousSelectionIds = next.map((s) => s.id);
  currentSelection = next;
  // Auto-anchor: single shape → slide; 2+ → reference (still overridable).
  setTarget(next.length > 1 ? "reference" : "slide");
  renderSelection();
}

/**
 * Fired on real selection changes (the Office event). Refreshes the pane, and —
 * if the eyedropper is armed — paints the newly selected shapes with the cached
 * color. Actions call refreshSelection() directly so they don't trigger painting.
 */
async function onSelectionChanged(): Promise<void> {
  await refreshSelection();
  if (currentSelection.length === 0) {
    return;
  }

  // Painter armed → paint the newly selected shapes.
  if (pickerArmed) {
    let n = 0;
    if (pickerArmed === "fill" && cachedColor) {
      n = await applyFillColor(cachedColor);
    } else if (pickerArmed === "line" && cachedColor) {
      n = await applyLineColor(cachedColor);
    } else if (pickerArmed === "format" && cachedFormat) {
      n = await applyFormat(cachedFormat);
    }
    if (n > 0) {
      const what = pickerArmed === "format" ? "format" : `${pickerArmed} ${cachedColor}`;
      setStatus(`Painted ${what} → ${n} shape(s). Click a tool to stop.`, "ok");
    }
    return;
  }

  // Otherwise auto-remember a single selected shape for "paste to slides", so
  // you don't need the explicit Copy button (Office.js can't read the OS
  // clipboard, so this is the closest thing to a normal copy → paste).
  if (currentSelection.length === 1) {
    const res = await captureElement(referenceId);
    if (res.element) {
      cachedElement = res.element;
      el("paste-cache-label").textContent =
        `Ready: ${res.element.kind} (auto-copied) — select slides, then Paste.`;
    }
  }
}

/**
 * The reference is the LAST shape the user selected. getSelectedShapes() returns
 * z-order (not click order — see the M0 spike), so we diff against the previous
 * selection: the newest-added shape wins; ties fall back to the last returned;
 * a manual pick sticks until the selection next changes.
 */
function pickReferenceId(
  current: ShapeProps[],
  previousIds: string[],
  currentRef: string | null
): string | null {
  if (current.length === 0) {
    return null;
  }
  const prev = new Set(previousIds);
  const added = current.filter((s) => !prev.has(s.id));
  if (added.length > 0) {
    return added[added.length - 1].id;
  }
  if (currentRef && current.some((s) => s.id === currentRef)) {
    return currentRef;
  }
  return current[current.length - 1].id;
}

function renderSelection(): void {
  const hint = el("selection-hint");
  const list = el("selection-list");
  list.innerHTML = "";

  if (currentSelection.length === 0) {
    hint.textContent = "Nothing selected.";
    referenceId = null;
    persistReference();
    return;
  }
  hint.textContent = `${currentSelection.length} selected — reference is the last one picked (click to override):`;
  if (!currentSelection.some((s) => s.id === referenceId)) {
    referenceId = currentSelection[currentSelection.length - 1].id;
  }
  persistReference();

  currentSelection.forEach((shape, i) => {
    const li = document.createElement("li");

    const radio = document.createElement("input");
    radio.type = "radio";
    radio.name = "reference";
    radio.checked = shape.id === referenceId;
    radio.addEventListener("change", () => {
      referenceId = shape.id;
      renderSelection();
    });

    const num = document.createElement("span");
    num.className = "order-num";
    num.textContent = String(i + 1);

    const label = document.createElement("label");
    label.style.flex = "1";
    label.style.cursor = "pointer";
    label.appendChild(radio);
    const name = document.createElement("span");
    name.textContent = " " + (shape.name || "(unnamed)");
    label.appendChild(name);
    if (shape.id === referenceId) {
      const badge = document.createElement("span");
      badge.className = "ref-badge";
      badge.textContent = "reference";
      label.appendChild(badge);
    }

    const meta = document.createElement("span");
    meta.className = "shape-meta";
    meta.textContent = `${Math.round(shape.width)}×${Math.round(shape.height)}`;

    li.appendChild(num);
    li.appendChild(label);
    li.appendChild(meta);
    list.appendChild(li);
  });
}

/** Share the current reference id with the ribbon commands runtime (same origin). */
function persistReference(): void {
  try {
    localStorage.setItem("shapeTools.referenceId", referenceId || "");
  } catch {
    /* localStorage unavailable — ribbon match-size falls back to last-in-selection */
  }
}

/* ---------- anchor toggle ---------- */

function setTarget(target: RelativeTarget): void {
  relativeTarget = target;
  document.querySelectorAll(".toggle-btn").forEach((btn) => {
    const active = (btn as HTMLElement).dataset.target === target;
    btn.classList.toggle("active", active);
    btn.setAttribute("aria-checked", String(active));
  });
  updateHints();
}

function updateHints(): void {
  el("target-hint").textContent =
    relativeTarget === "reference"
      ? "2+ shapes → anchored to the reference shape (auto; click to override)."
      : "1 shape → anchored to the slide (auto; click to override).";
}

/** The reference shape from the current selection, or null (with a status set) if unusable. */
function resolveReference(shapes: ShapeProps[]): ShapeProps | null {
  if (shapes.length < 2) {
    setStatus("Select at least 2 shapes (the reference plus the ones to move).", "error");
    return null;
  }
  const ref = shapes.find((s) => s.id === referenceId) ?? null;
  if (!ref) {
    setStatus("Pick a reference shape in the selection list first.", "error");
    return null;
  }
  return ref;
}

const NO_SLIDE_SIZE =
  "This PowerPoint can’t report slide size (needs 1.10). Use “Reference” instead.";

/* ---------- M1 Align + M2 Dock ---------- */

async function onAlign(edge: AlignEdge): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  let anchor: Bounds;
  if (relativeTarget === "reference") {
    const ref = resolveReference(shapes);
    if (!ref) {
      return;
    }
    anchor = referenceAnchor(ref);
  } else {
    const slide = await getSlideSize();
    if (!slide) {
      setStatus(NO_SLIDE_SIZE, "error");
      return;
    }
    anchor = slideAnchor(slide);
  }
  const updated = alignToAnchor(shapes, edge, anchor);
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  setStatus(`Aligned ${shapes.length} shape(s): ${edge} → ${relativeTarget}.`, "ok");
}

async function onDock(edge: DockEdge): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  let updated: ShapeProps[];
  if (relativeTarget === "reference") {
    const ref = resolveReference(shapes);
    if (!ref) {
      return;
    }
    updated = dockToReference(shapes, edge, ref);
  } else {
    const slide = await getSlideSize();
    if (!slide) {
      setStatus(NO_SLIDE_SIZE, "error");
      return;
    }
    updated = dockToSlide(shapes, edge, slide);
  }
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  setStatus(`Docked ${shapes.length} shape(s): ${edge} → ${relativeTarget}.`, "ok");
}

/* ---------- M3 Distribute ---------- */

async function onDistribute(axis: DistributeAxis): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length < 3) {
    setStatus("Select at least 3 shapes to distribute.", "error");
    return;
  }
  let updated: ShapeProps[];
  if (relativeTarget === "reference") {
    updated = distributeAcrossSelection(shapes, axis);
  } else {
    const slide = await getSlideSize();
    if (!slide) {
      setStatus(NO_SLIDE_SIZE, "error");
      return;
    }
    updated = distributeAcrossSlide(shapes, axis, slide);
  }
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  const scope = relativeTarget === "reference" ? "selection" : "slide";
  setStatus(`Distributed ${shapes.length} shape(s) ${axis} across ${scope}.`, "ok");
}

/* ---------- M4 Size ---------- */

async function onSize(mode: SizeMode): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  const ref = resolveReference(shapes);
  if (!ref) {
    return;
  }
  const updated = sizeToReference(shapes, mode, ref);
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  setStatus(`Sized ${shapes.length - 1} shape(s) to the reference (${mode}).`, "ok");
}

/* ---------- M5 Swap ---------- */

async function onSwap(): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length !== 2) {
    setStatus("Select exactly 2 shapes to swap.", "error");
    return;
  }
  const alsoSwapSize = (el("swap-size") as HTMLInputElement).checked;
  const updated = swapTwo(shapes, alsoSwapSize);
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  setStatus(`Swapped the two shapes${alsoSwapSize ? " (incl. size)" : ""}.`, "ok");
}

/* ---------- M6 Magic Resizer ---------- */

interface TypoAttrs {
  lineWeight: boolean;
  fontSize: boolean;
}

function readTypoAttrs(): TypoAttrs {
  return {
    lineWeight: (el("attr-line") as HTMLInputElement).checked,
    fontSize: (el("attr-font") as HTMLInputElement).checked,
  };
}

async function scaleTypographyForAttrs(factor: number, attrs: TypoAttrs): Promise<string> {
  if (!attrs.lineWeight && !attrs.fontSize) {
    return "";
  }
  const res = await scaleTypography(factor, attrs);
  const parts: string[] = [];
  if (attrs.fontSize) {
    parts.push(`font ×${res.changedFonts}`);
  }
  if (attrs.lineWeight) {
    parts.push(`line ×${res.changedLines}`);
  }
  let note = parts.length ? ` [${parts.join(", ")}]` : "";
  if (res.unreadableFonts > 0) {
    note += ` — ${res.unreadableFonts} box(es) had no readable font size`;
  }
  if (res.skippedLongMixed.length > 0) {
    note += ` — skipped long mixed text: ${res.skippedLongMixed.join(", ")}`;
  }
  return note;
}

async function onScale(): Promise<void> {
  const pct = parseFloat((el("resize-percent") as HTMLInputElement).value);
  if (!isFinite(pct) || pct <= 0) {
    setStatus("Enter a percentage greater than 0.", "error");
    return;
  }
  const factor = pct / 100;
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  const updated = scaleSelection(shapes, factor, scaleDimension);
  await applyShapes(updated);
  const note = await scaleTypographyForAttrs(factor, readTypoAttrs());
  await refreshSelection();
  (el("resize-percent") as HTMLInputElement).value = "100";
  setStatus(`Scaled ${shapes.length} shape(s) to ${pct}% (${scaleDimension}).${note}`, "ok");
}

async function onAbsolute(): Promise<void> {
  const wRaw = parseFloat((el("abs-width") as HTMLInputElement).value);
  const hRaw = parseFloat((el("abs-height") as HTMLInputElement).value);
  const width = isFinite(wRaw) && wRaw > 0 ? wRaw : undefined;
  const height = isFinite(hRaw) && hRaw > 0 ? hRaw : undefined;
  if (width === undefined && height === undefined) {
    setStatus("Enter a width and/or height (pt) in the Magic resizer row.", "error");
    return;
  }
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  const updated = setAbsoluteSize(shapes, width, height);
  await applyShapes(updated);
  currentSelection = updated;
  renderSelection();
  const dims = [width !== undefined ? `w=${width}` : "", height !== undefined ? `h=${height}` : ""]
    .filter(Boolean)
    .join(", ");
  setStatus(`Set ${shapes.length} shape(s) to ${dims} pt.`, "ok");
}

async function onFit(mode: FitMode): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shapes on the slide first.", "error");
    return;
  }
  const slide = await getSlideSize();
  if (!slide) {
    setStatus(NO_SLIDE_SIZE, "error");
    return;
  }
  const { shapes: updated, factor } = fitToSlide(shapes, slide, mode);
  await applyShapes(updated);
  const note = await scaleTypographyForAttrs(factor, readTypoAttrs());
  await refreshSelection();
  const verb = mode === "fit" ? "Fit" : "Filled";
  setStatus(`${verb} ${shapes.length} shape(s) to slide (×${factor.toFixed(2)}).${note}`, "ok");
}

/* ---------- M10 Copy to ---------- */

async function onCopyTo(direction: CopyDirection): Promise<void> {
  const gapRaw = parseFloat((el("copy-gap") as HTMLInputElement).value);
  const gap = isFinite(gapRaw) && gapRaw >= 0 ? gapRaw : 0;
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shape(s) to copy first.", "error");
    return;
  }
  const res = await copyShapesTo(direction, gap);
  await refreshSelection();
  const total = res.reconstructed + res.flattened.length;
  let msg = `Copied ${total} shape(s) ${direction}.`;
  if (res.outlineApprox.length > 0) {
    msg += ` Outline not preserved (copied as rectangle): ${res.outlineApprox.join(", ")}.`;
  }
  if (res.flattened.length > 0) {
    msg += ` Flattened to image — not editable: ${res.flattened.join(", ")}.`;
  }
  setStatus(msg, "ok");
}

/* ---------- M7 Text boxes ---------- */

async function onMerge(): Promise<void> {
  const res = await mergeTextBoxes(referenceId);
  if (!res.merged) {
    setStatus("Select at least 2 text boxes (with text) to merge.", "error");
    return;
  }
  await refreshSelection();
  setStatus(
    `Merged ${res.count} text boxes into the reference. Per-run formatting of merged-in text isn't preserved.`,
    "ok"
  );
}

async function onSplit(mode: SplitMode): Promise<void> {
  const res = await splitTextBox(referenceId, mode);
  if (res.count === 0) {
    setStatus("Select one text box with text to split (or pick a reference).", "error");
    return;
  }
  if (res.count === 1) {
    setStatus(`Nothing to split — the box has only one ${mode}.`, "error");
    return;
  }
  await refreshSelection();
  setStatus(`Split into ${res.count} boxes (by ${mode}).`, "ok");
}

/* ---------- M11 Text box fit ---------- */

async function onTextFit(mode: AutoSizeMode): Promise<void> {
  const n = await setAutoSize(mode);
  await refreshSelection();
  const label = mode === "shapeToText" ? "shape → text" : "off";
  setStatus(
    n > 0 ? `Auto-fit set on ${n} shape(s): ${label}.` : "No text-capable shapes selected.",
    n > 0 ? "ok" : ""
  );
}

async function onShrinkFont(): Promise<void> {
  const n = await shrinkFontToFit();
  await refreshSelection();
  setStatus(
    n > 0
      ? `Shrank font to fit on ${n} shape(s).`
      : "Nothing to shrink (text already fits, or no text selected).",
    n > 0 ? "ok" : ""
  );
}

/* ---------- M12 Color eyedropper ---------- */

async function onPick(kind: ColorKind): Promise<void> {
  // Click the armed eyedropper again to turn it off.
  if (pickerArmed === kind) {
    disarmPicker();
    setStatus("Eyedropper off.", "");
    return;
  }
  const res = await readMasterColor(referenceId, kind);
  if (res.problem || !res.color) {
    setStatus(res.problem || "Couldn't read a color.", "error");
    return;
  }
  cachedColor = res.color;
  pickerArmed = kind;
  updatePickerUI();
  setStatus(
    `Picked ${kind} ${cachedColor}. Now click shapes to paint them; click the eyedropper again to stop.`,
    "ok"
  );
}

async function onCopyFormat(): Promise<void> {
  if (pickerArmed === "format") {
    disarmPicker();
    setStatus("Format painter off.", "");
    return;
  }
  const res = await readFormat(referenceId);
  if (res.problem || !res.format) {
    setStatus(res.problem || "Couldn't read the formatting.", "error");
    return;
  }
  cachedFormat = res.format;
  pickerArmed = "format";
  updatePickerUI();
  setStatus("Copied format. Now click shapes to apply it; click the brush again to stop.", "ok");
}

function disarmPicker(): void {
  pickerArmed = null;
  updatePickerUI();
}

/* ---------- M13 Paste to slides ---------- */

async function onCaptureElement(): Promise<void> {
  const res = await captureElement(referenceId);
  if (res.problem || !res.element) {
    setStatus(res.problem || "Couldn't copy the element.", "error");
    return;
  }
  cachedElement = res.element;
  el("paste-cache-label").textContent = res.summary || "Element copied.";
  setStatus(`${res.summary} Select target slides in the thumbnails, then Paste to slides.`, "ok");
}

async function onPasteToSlides(): Promise<void> {
  if (!cachedElement) {
    setStatus("Copy an element first (select a shape → Copy element).", "error");
    return;
  }
  const res = await pasteToSelectedSlides(cachedElement);
  if (res.problem) {
    setStatus(res.problem, "error");
    return;
  }
  setStatus(`Pasted the element onto ${res.slides} slide(s).`, "ok");
}

/* ---------- M14 Decompose table ---------- */

async function onDecompose(): Promise<void> {
  const res = await decomposeTable(referenceId);
  if (res.problem) {
    setStatus(res.problem, "error");
    return;
  }
  await refreshSelection();
  setStatus(`Decomposed table → ${res.boxes} text box(es) beside it. ${res.note || ""}`, "ok");
}

function updatePickerUI(): void {
  document.querySelectorAll(".ibtn").forEach((b) => {
    const id = (b as HTMLElement).dataset.action;
    const armed =
      (id === "color.pickFill" && pickerArmed === "fill") ||
      (id === "color.pickLine" && pickerArmed === "line") ||
      (id === "format.copy" && pickerArmed === "format");
    b.classList.toggle("active", armed);
  });
  const swatch = el("color-cache");
  const label = el("color-cache-label");
  if (pickerArmed === "format") {
    swatch.style.background = "transparent";
    label.textContent = "format captured (armed)";
  } else {
    swatch.style.background = cachedColor || "transparent";
    label.textContent = cachedColor
      ? `${cachedColor}${pickerArmed ? ` · ${pickerArmed} (armed)` : ""}`
      : "nothing yet";
  }
}

/* ---------- M8 Hide / Unhide ---------- */

async function onHide(): Promise<void> {
  const shapes = await readSelectedShapes();
  if (shapes.length === 0) {
    setStatus("Select shape(s) to hide first.", "error");
    return;
  }
  const n = await hideShapes();
  await refreshSelection();
  setStatus(
    n > 0
      ? `Hid ${n} shape(s). Reach them via the Selection Pane.`
      : "Those shapes are already hidden.",
    "ok"
  );
}

async function onUnhideAll(): Promise<void> {
  const n = await unhideAllOnSlide();
  await refreshSelection();
  setStatus(
    n > 0 ? `Unhid ${n} shape(s) on this slide.` : "No hidden shapes on this slide.",
    n > 0 ? "ok" : ""
  );
}

/* ---------- M9 Select similar ---------- */

async function onSelectSimilar(): Promise<void> {
  const criteria = {
    type: (el("sim-type") as HTMLInputElement).checked,
    fill: (el("sim-fill") as HTMLInputElement).checked,
    lineColor: (el("sim-line-color") as HTMLInputElement).checked,
    lineStyle: (el("sim-line-style") as HTMLInputElement).checked,
    width: (el("sim-width") as HTMLInputElement).checked,
    height: (el("sim-height") as HTMLInputElement).checked,
  };
  if (!Object.values(criteria).some(Boolean)) {
    setStatus("Tick at least one criterion.", "error");
    return;
  }
  const res = await selectSimilar(referenceId, criteria);
  if (!res.refFound) {
    setStatus("Pick a reference shape first (select one on the slide).", "error");
    return;
  }
  await refreshSelection();
  let msg = `Selected ${res.count} matching shape(s).`;
  if (res.isWeb) {
    msg += " On PowerPoint web this is unreliable — double-check the selection.";
  }
  setStatus(msg, "ok");
}

/* ---------- tooltips ---------- */

function showTip(node: HTMLElement): void {
  const tip = el("tip");
  const name = node.dataset.tip || "";
  const desc = node.dataset.desc || "";
  const action = node.dataset.action;
  const combo = action ? shortcutByAction[action] : undefined;
  tip.innerHTML =
    `<b>${escapeHtml(name)}</b>${escapeHtml(desc)}` +
    (combo ? `<span class="tip-key">Shortcut: ${escapeHtml(combo)}</span>` : "");
  tip.hidden = false;

  const r = node.getBoundingClientRect();
  const tr = tip.getBoundingClientRect();
  // Centered above the icon by default; flip below only if there's no room above.
  let left = r.left + r.width / 2 - tr.width / 2;
  if (left < 6) {
    left = 6;
  }
  if (left + tr.width > window.innerWidth - 6) {
    left = window.innerWidth - tr.width - 6;
  }
  let top = r.top - tr.height - 6;
  if (top < 6) {
    top = r.bottom + 6;
  }
  tip.style.left = `${left}px`;
  tip.style.top = `${top}px`;
}

function hideTip(): void {
  el("tip").hidden = true;
}

/* ---------- keyboard shortcuts ---------- */

let assignMode = false;
let recordingId: string | null = null;
let recordingBtn: HTMLElement | null = null;
/** actionId → combo string (e.g. "Ctrl+Alt+L"). */
let shortcutByAction: Record<string, string> = {};
const STORAGE_KEY = "shapeTools.shortcuts";

function loadShortcuts(): void {
  try {
    shortcutByAction = JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}");
  } catch {
    shortcutByAction = {};
  }
  updateShortcutBadges();
}

function saveShortcuts(): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(shortcutByAction));
  updateShortcutBadges();
}

function updateShortcutBadges(): void {
  document.querySelectorAll(".ibtn").forEach((b) => {
    const id = (b as HTMLElement).dataset.action;
    b.classList.toggle("has-key", !!(id && shortcutByAction[id]));
  });
}

function toggleAssignMode(): void {
  assignMode = !assignMode;
  el("btn-shortcuts").classList.toggle("active", assignMode);
  document.body.classList.toggle("assign", assignMode);
  el("shortcut-banner").hidden = !assignMode;
  stopRecording();
  setStatus(assignMode ? "Shortcut mode on — click a tool, then press a key combo." : "", "");
}

function startRecording(id: string, btn: HTMLElement): void {
  stopRecording();
  recordingId = id;
  recordingBtn = btn;
  btn.classList.add("recording");
  setStatus(
    `Press a shortcut for “${btn.dataset.tip || id}” (Ctrl/Alt + key). Esc cancels, Backspace clears.`,
    ""
  );
}

function stopRecording(): void {
  if (recordingBtn) {
    recordingBtn.classList.remove("recording");
  }
  recordingId = null;
  recordingBtn = null;
}

function comboFromEvent(e: KeyboardEvent): string | null {
  const k = e.key;
  if (k === "Control" || k === "Shift" || k === "Alt" || k === "Meta") {
    return null;
  }
  const parts: string[] = [];
  if (e.ctrlKey) {
    parts.push("Ctrl");
  }
  if (e.altKey) {
    parts.push("Alt");
  }
  if (e.shiftKey) {
    parts.push("Shift");
  }
  if (e.metaKey) {
    parts.push("Meta");
  }
  parts.push(k.length === 1 ? k.toUpperCase() : k);
  return parts.join("+");
}

function onKeyDown(e: KeyboardEvent): void {
  // Recording a new shortcut for a clicked tool.
  if (recordingId) {
    if (e.key === "Escape") {
      stopRecording();
      setStatus("Shortcut cancelled.", "");
      e.preventDefault();
      return;
    }
    if (e.key === "Backspace" || e.key === "Delete") {
      delete shortcutByAction[recordingId];
      saveShortcuts();
      setStatus("Shortcut cleared.", "ok");
      stopRecording();
      e.preventDefault();
      return;
    }
    const combo = comboFromEvent(e);
    if (!combo) {
      return; // modifier-only keydown, wait for the real key
    }
    const isFn = /^F\d+$/.test(e.key);
    if (!e.ctrlKey && !e.altKey && !e.metaKey && !isFn) {
      setStatus("Use Ctrl or Alt with a key (e.g. Ctrl+Alt+L).", "error");
      e.preventDefault();
      return;
    }
    // Ensure the combo is unique — drop it from any other action.
    for (const other of Object.keys(shortcutByAction)) {
      if (shortcutByAction[other] === combo) {
        delete shortcutByAction[other];
      }
    }
    shortcutByAction[recordingId] = combo;
    saveShortcuts();
    setStatus(`Bound ${combo}.`, "ok");
    stopRecording();
    e.preventDefault();
    return;
  }

  // Otherwise, fire a bound shortcut (unless typing in a field or assigning).
  if (assignMode) {
    return;
  }
  const active = document.activeElement as HTMLElement | null;
  if (active && active.tagName === "INPUT") {
    return;
  }
  const combo = comboFromEvent(e);
  if (!combo) {
    return;
  }
  const match = Object.keys(shortcutByAction).find((id) => shortcutByAction[id] === combo);
  if (match && ACTIONS[match]) {
    e.preventDefault();
    guard(async () => {
      await ACTIONS[match]();
    });
  }
}

/* ---------- small utilities ---------- */

function el(id: string): HTMLElement {
  const node = document.getElementById(id);
  if (!node) {
    throw new Error(`Missing element #${id}`);
  }
  return node;
}

function setStatus(message: string, kind: "ok" | "error" | "" = ""): void {
  const status = el("status");
  status.textContent = message;
  status.className = "status" + (kind ? " " + kind : "");
}

async function guard(fn: () => Promise<void>): Promise<void> {
  try {
    await fn();
  } catch (err) {
    if (err instanceof UnsupportedError) {
      setStatus(err.message, "error");
    } else {
      setStatus(
        "Something went wrong: " + (err instanceof Error ? err.message : String(err)),
        "error"
      );
    }
  }
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) => {
    switch (c) {
      case "&":
        return "&amp;";
      case "<":
        return "&lt;";
      case ">":
        return "&gt;";
      case '"':
        return "&quot;";
      default:
        return "&#39;";
    }
  });
}
