/*
 * M10 — Copy to (above / below / left / right).
 *
 * Pure placement math: given a source's bounding box, a direction, and a gap,
 * where does the copy go? The copy is the same size as the source.
 *   - left/right keep the source's top (copy at source.left ± (width + gap))
 *   - above/below keep the source's left (copy at source.top ± (height + gap))
 * A gap of 0 places the copy flush against the source.
 *
 * The actual duplication (reconstruction / image fallback) lives in the office
 * adapter, since Office.js has no native duplicate.
 */

import { Bounds } from "./types";

export type CopyDirection = "above" | "below" | "left" | "right";

export function copyPlacement(
  source: Bounds,
  direction: CopyDirection,
  gap: number
): { left: number; top: number } {
  switch (direction) {
    case "right":
      return { left: source.left + source.width + gap, top: source.top };
    case "left":
      return { left: source.left - source.width - gap, top: source.top };
    case "below":
      return { left: source.left, top: source.top + source.height + gap };
    case "above":
      return { left: source.left, top: source.top - source.height - gap };
    default:
      return { left: source.left, top: source.top };
  }
}
