/*
 * M7 — Text box merge / split (pure helpers).
 *
 * The Office.js plumbing (reading text, creating/deleting boxes) lives in the
 * office adapter; here we keep only the text-parsing decisions.
 *
 * NOTE: split-at-cursor is intentionally NOT supported — Office.js exposes no
 * caret position. Split is by paragraph or by line only.
 */

export type SplitMode = "paragraph" | "line";

/**
 * Splits text into non-empty pieces.
 *  - "paragraph": on hard paragraph breaks (CR / LF).
 *  - "line": also on soft line breaks (vertical tab, i.e. Shift+Enter).
 * Blank pieces are dropped so we don't create empty boxes.
 */
export function splitText(text: string, mode: SplitMode): string[] {
  const separators = mode === "paragraph" ? /\r\n|\r|\n/ : /\r\n|\r|\n|\v/;
  return text.split(separators).filter((piece) => piece.trim().length > 0);
}
