/*
 * M4 — Size (match the reference shape).
 *
 * Sets each selected shape's width and/or height equal to the reference shape's.
 * Position (left/top) is untouched, so shapes grow/shrink from their top-left
 * corner — the same anchoring PowerPoint uses when you set width/height. The
 * reference shape itself is returned unchanged.
 *
 * This operation is inherently reference-based (there's a shape to match), so it
 * ignores the reference/slide toggle. Matching a shape to the slide's dimensions
 * is a fill operation and belongs to M6.
 */

import { ShapeProps } from "./types";

export type SizeMode = "width" | "height" | "both";

export function sizeToReference(
  shapes: ReadonlyArray<ShapeProps>,
  mode: SizeMode,
  reference: ShapeProps
): ShapeProps[] {
  return shapes.map((s) => {
    if (s.id === reference.id) {
      return { ...s };
    }
    const next = { ...s };
    if (mode === "width" || mode === "both") {
      next.width = reference.width;
    }
    if (mode === "height" || mode === "both") {
      next.height = reference.height;
    }
    return next;
  });
}
