/*
 * PowerPoint selection adapter.
 *
 * This is the thin Office.js layer that turns the live selection into the
 * engine's plain `ShapeProps` records and back. M0's job is narrow: read the
 * selection so the task pane can answer THE spike question —
 *
 *     Does getSelectedShapes() preserve the user's click order?
 *
 * We deliberately load only id/name/type/geometry here (cheap sync, no
 * requirement-gated fill/line/font). Later milestones extend the loaded
 * property set as they need it.
 */

/* global PowerPoint */

import { ShapeProps } from "../core";
import { isSupported } from "./capabilities";

export class UnsupportedError extends Error {
  constructor(public readonly requirement: string) {
    super(`This PowerPoint version does not support the API needed to ${requirement}.`);
    this.name = "UnsupportedError";
  }
}

/**
 * Reads the currently selected shapes, in the exact order the API returns them.
 *
 * IMPORTANT for the spike: we do NOT sort or reorder. The order of the returned
 * array is precisely what getSelectedShapes() yielded, so the task pane can
 * compare it against the order the user clicked.
 */
export async function readSelectedShapes(): Promise<ShapeProps[]> {
  if (!isSupported("selectedShapes")) {
    throw new UnsupportedError("read the selected shapes");
  }

  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load(
      "items/id,items/name,items/type,items/left,items/top,items/width,items/height,items/rotation"
    );
    await context.sync();

    return selected.items.map((s) => ({
      id: s.id,
      name: s.name,
      type: s.type as unknown as string,
      left: s.left,
      top: s.top,
      width: s.width,
      height: s.height,
      rotation: s.rotation,
    }));
  });
}

/**
 * M0 spike-support helper: drops four labeled rectangles (A, B, C, D) onto the
 * current slide at distinct, easy-to-see positions. The user then clicks them
 * in a known order and uses "Read selection order" to see whether the API
 * hands them back in that order. Non-destructive: it only adds shapes.
 */
export async function insertSpikeTestShapes(): Promise<void> {
  const labels = ["A", "B", "C", "D"];
  // Stagger both axes so click order, z-order, and left-to-right order are all
  // distinguishable in the readout.
  const layout = [
    { left: 60, top: 60 },
    { left: 320, top: 180 },
    { left: 140, top: 300 },
    { left: 420, top: 90 },
  ];

  await PowerPoint.run(async (context) => {
    const slide = context.presentation.getSelectedSlides().getItemAt(0);
    labels.forEach((label, i) => {
      const shape = slide.shapes.addGeometricShape(PowerPoint.GeometricShapeType.rectangle, {
        left: layout[i].left,
        top: layout[i].top,
        width: 120,
        height: 90,
      });
      shape.name = `Test ${label}`;
      shape.textFrame.textRange.text = label;
    });
    await context.sync();
  });
}
