/*
 * Document-level events. Currently just selection tracking, so the pane can
 * mirror the live selection instead of making the user press a "read" button.
 */

/* global Office */

/**
 * Registers a handler that fires whenever the user's selection changes in the
 * document. Resolves once the handler is registered. The handler is called with
 * no useful payload — re-read the selection via readSelectedShapes().
 *
 * Note: actions never depend on this event for correctness (they re-read the
 * selection themselves). It only keeps the displayed list fresh, so if a given
 * host is stingy about firing it, the tools still behave correctly.
 */
export function addSelectionChangedHandler(handler: () => void): Promise<void> {
  return new Promise((resolve, reject) => {
    Office.context.document.addHandlerAsync(
      Office.EventType.DocumentSelectionChanged,
      handler,
      (result) => {
        if (result.status === Office.AsyncResultStatus.Succeeded) {
          resolve();
        } else {
          reject(
            new Error(result.error ? result.error.message : "Could not register selection handler.")
          );
        }
      }
    );
  });
}
