/*
 * M6 — Magic Resizer (geometry half).
 *
 * Pure size/position math. The typography half (line weight + per-run font
 * scaling) lives in the office adapter, since it needs live text-run access
 * that ShapeProps doesn't model. Both halves share the same scale factor so a
 * "150%" resize grows the box, its outline, and its text together.
 *
 * Percentage and absolute resizes are CENTER-anchored: a shape stays centered
 * where it was and grows/shrinks around its middle (what you want from a bulk
 * resizer). Fit/Fill treat the selection as one group and scale it about the
 * group's bounding box, then center the result on the slide.
 */

import { ShapeProps, SlideSize } from "./types";
import { centerX, centerY, unionBounds } from "./geometry";

export type FitMode = "fit" | "fill";

/** Which axes a scale applies to. */
export type ScaleDimension = "both" | "width" | "height";

/**
 * Scale the whole selection about its center, scaling BOTH element sizes and the
 * gaps between them — so a grid stays a proportional grid (a 2×2 matrix at 200%
 * becomes the same 2×2 layout at double the footprint, spacing intact, instead
 * of overlapping blobs). `dimension` restricts it to one axis:
 *   - "width"  grows horizontally  (widths + horizontal gaps)
 *   - "height" grows vertically    (heights + vertical gaps)
 *   - "both"   grows uniformly
 * A single shape simply scales about its own center. Works for any shape whose
 * bounding box can be set, including lines.
 */
export function scaleSelection(
  shapes: ReadonlyArray<ShapeProps>,
  factor: number,
  dimension: ScaleDimension
): ShapeProps[] {
  const b = unionBounds(shapes);
  if (!b) {
    return shapes.map((s) => ({ ...s }));
  }
  const gcx = b.left + b.width / 2;
  const gcy = b.top + b.height / 2;
  const fx = dimension === "height" ? 1 : factor;
  const fy = dimension === "width" ? 1 : factor;
  return shapes.map((s) => ({
    ...s,
    left: gcx + (s.left - gcx) * fx,
    width: s.width * fx,
    top: gcy + (s.top - gcy) * fy,
    height: s.height * fy,
  }));
}

/** Set an absolute width and/or height (points), keeping each shape centered. */
export function setAbsoluteSize(
  shapes: ReadonlyArray<ShapeProps>,
  width: number | undefined,
  height: number | undefined
): ShapeProps[] {
  return shapes.map((s) => {
    const cx = centerX(s);
    const cy = centerY(s);
    const w = width ?? s.width;
    const h = height ?? s.height;
    return { ...s, width: w, height: h, left: cx - w / 2, top: cy - h / 2 };
  });
}

/**
 * Scale the whole selection as a group to fit within ("fit") or cover ("fill")
 * the slide, then center it. Returns the scaled shapes and the factor used, so
 * the caller can scale line weight / font by the same amount.
 */
export function fitToSlide(
  shapes: ReadonlyArray<ShapeProps>,
  slide: SlideSize,
  mode: FitMode
): { shapes: ShapeProps[]; factor: number } {
  const b = unionBounds(shapes);
  if (!b || b.width === 0 || b.height === 0) {
    return { shapes: shapes.map((s) => ({ ...s })), factor: 1 };
  }
  const fx = slide.width / b.width;
  const fy = slide.height / b.height;
  const factor = mode === "fit" ? Math.min(fx, fy) : Math.max(fx, fy);

  const newW = b.width * factor;
  const newH = b.height * factor;
  const offsetX = (slide.width - newW) / 2;
  const offsetY = (slide.height - newH) / 2;

  const scaled = shapes.map((s) => ({
    ...s,
    left: offsetX + (s.left - b.left) * factor,
    top: offsetY + (s.top - b.top) * factor,
    width: s.width * factor,
    height: s.height * factor,
  }));
  return { shapes: scaled, factor };
}
