/*
 * Slide-level info from the active presentation.
 */

/* global PowerPoint */

import { SlideSize } from "../core";
import { isSupported } from "./capabilities";

/**
 * Returns the slide size in points, or null if this PowerPoint build is too old
 * to report it (PageSetup is PowerPointApi 1.10). Callers degrade gracefully —
 * e.g. "align to slide" tells the user to use "align to reference" instead.
 */
export async function getSlideSize(): Promise<SlideSize | null> {
  if (!isSupported("pageSetup")) {
    return null;
  }
  return PowerPoint.run(async (context) => {
    const ps = context.presentation.pageSetup;
    ps.load("slideWidth,slideHeight");
    await context.sync();
    return { width: ps.slideWidth, height: ps.slideHeight };
  });
}
