/*
 * Pure geometry helpers. No Office.js, no DOM, no side effects — every function
 * here is a plain input→output transform so it can be unit-tested in isolation
 * and reused by any host adapter.
 *
 * Note on rotation: these helpers use the shape's *unrotated* bounding box
 * (left/top/width/height), which is what PowerPoint reports and what alignment
 * tools conventionally operate on. Rotation-aware bounds can be layered on later
 * without changing this contract.
 */

import { Bounds, ShapeProps } from "./types";

export function right(b: Bounds): number {
  return b.left + b.width;
}

export function bottom(b: Bounds): number {
  return b.top + b.height;
}

export function centerX(b: Bounds): number {
  return b.left + b.width / 2;
}

export function centerY(b: Bounds): number {
  return b.top + b.height / 2;
}

/** Axis-aligned bounding box that encloses every shape in the list. */
export function unionBounds(shapes: ReadonlyArray<Bounds>): Bounds | null {
  if (shapes.length === 0) {
    return null;
  }
  let minLeft = Infinity;
  let minTop = Infinity;
  let maxRight = -Infinity;
  let maxBottom = -Infinity;
  for (const s of shapes) {
    minLeft = Math.min(minLeft, s.left);
    minTop = Math.min(minTop, s.top);
    maxRight = Math.max(maxRight, right(s));
    maxBottom = Math.max(maxBottom, bottom(s));
  }
  return { left: minLeft, top: minTop, width: maxRight - minLeft, height: maxBottom - minTop };
}

/**
 * Orders items top-to-bottom, then left-to-right (natural reading order). A small
 * vertical tolerance groups near-aligned items into the same row. Used to merge
 * text boxes in a sensible reading order.
 */
export function readingOrder<T extends { top: number; left: number }>(
  items: ReadonlyArray<T>
): T[] {
  const ROW_TOLERANCE = 2;
  return [...items].sort((a, b) =>
    Math.abs(a.top - b.top) > ROW_TOLERANCE ? a.top - b.top : a.left - b.left
  );
}

/**
 * Returns a shallow-cloned shape with a new left/top. The engine's convention
 * is to never mutate its inputs — callers get back a fresh object they can diff
 * against the original to compute the minimal set of writes.
 */
export function moveTo(shape: ShapeProps, left: number, top: number): ShapeProps {
  return { ...shape, left, top };
}
