/*
 * M12b — Format painter.
 *
 * Reads the WHOLE look of the reference shape (fill, line, and range-level font)
 * into a plain object, then applies it to other selected shapes. Like the color
 * eyedropper but for full formatting.
 *
 * Everything is guarded by shape type (loading fill/line/textFrame on a shape
 * that lacks them throws). Font is copied at the range level, so a target's
 * mixed per-run sizes are flattened — the same trade-off PowerPoint's own format
 * painter makes.
 */

/* global PowerPoint */

const FILL_TYPES = new Set(["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"]);
const LINE_TYPES = new Set([
  "GeometricShape",
  "TextBox",
  "Placeholder",
  "Callout",
  "Freeform",
  "Line",
]);
const TEXT_TYPES = new Set(["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"]);

export interface ShapeFormat {
  fillType?: string;
  fillColor?: string;
  fillTransparency?: number;
  lineVisible?: boolean;
  lineColor?: string;
  lineWeight?: number;
  lineDash?: string;
  lineStyle?: string;
  fontName?: string | null;
  fontSize?: number | null;
  fontBold?: boolean | null;
  fontItalic?: boolean | null;
  fontUnderline?: string | null;
  fontColor?: string | null;
  /** True if at least one facet was captured. */
  any?: boolean;
}

export interface FormatReadResult {
  format?: ShapeFormat;
  problem?: string;
}

/** Reads the reference shape's fill + line + font into a ShapeFormat. */
export async function readFormat(referenceId: string | null): Promise<FormatReadResult> {
  if (!referenceId) {
    return { problem: "Select the shape to copy formatting from first." };
  }
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();

    const source =
      selected.items.find((s) => s.id === referenceId) || selected.items[selected.items.length - 1];
    if (!source) {
      return { problem: "Select the shape to copy formatting from first." };
    }
    const type = source.type as unknown as string;
    const hasFill = FILL_TYPES.has(type);
    const hasLine = LINE_TYPES.has(type);
    const hasText = TEXT_TYPES.has(type);

    if (hasFill) {
      source.fill.load("type,foregroundColor,transparency");
    }
    if (hasLine) {
      source.lineFormat.load("visible,color,weight,dashStyle,style");
    }
    if (hasText) {
      source.textFrame.textRange.font.load("name,size,bold,italic,underline,color");
    }
    await context.sync();

    const fmt: ShapeFormat = {};
    if (hasFill) {
      fmt.fillType = source.fill.type as unknown as string;
      if (fmt.fillType === "Solid") {
        fmt.fillColor = source.fill.foregroundColor;
        fmt.fillTransparency = source.fill.transparency;
      }
      fmt.any = true;
    }
    if (hasLine) {
      fmt.lineVisible = source.lineFormat.visible;
      fmt.lineColor = source.lineFormat.color;
      fmt.lineWeight = source.lineFormat.weight;
      fmt.lineDash = source.lineFormat.dashStyle as unknown as string;
      fmt.lineStyle = source.lineFormat.style as unknown as string;
      fmt.any = true;
    }
    if (hasText) {
      const f = source.textFrame.textRange.font;
      fmt.fontName = f.name;
      fmt.fontSize = f.size;
      fmt.fontBold = f.bold;
      fmt.fontItalic = f.italic;
      fmt.fontUnderline = f.underline as unknown as string | null;
      fmt.fontColor = f.color;
      fmt.any = true;
    }
    if (!fmt.any) {
      return { problem: "That shape has no copyable formatting." };
    }
    return { format: fmt };
  });
}

/** Applies a captured format to every compatible selected shape; returns the count touched. */
export async function applyFormat(fmt: ShapeFormat): Promise<number> {
  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();

    let count = 0;
    for (const s of selected.items) {
      const type = s.type as unknown as string;
      let touched = false;

      if (fmt.fillType !== undefined && FILL_TYPES.has(type)) {
        if (fmt.fillType === "NoFill") {
          s.fill.clear();
        } else if (fmt.fillType === "Solid" && fmt.fillColor) {
          s.fill.setSolidColor(fmt.fillColor);
          if (typeof fmt.fillTransparency === "number") {
            s.fill.transparency = fmt.fillTransparency;
          }
        }
        touched = true;
      }

      if (fmt.lineVisible !== undefined && LINE_TYPES.has(type)) {
        s.lineFormat.visible = fmt.lineVisible;
        if (fmt.lineVisible) {
          if (fmt.lineColor) {
            s.lineFormat.color = fmt.lineColor;
          }
          if (typeof fmt.lineWeight === "number") {
            s.lineFormat.weight = fmt.lineWeight;
          }
          if (fmt.lineDash) {
            s.lineFormat.dashStyle = fmt.lineDash as unknown as PowerPoint.ShapeLineDashStyle;
          }
          if (fmt.lineStyle) {
            s.lineFormat.style = fmt.lineStyle as unknown as PowerPoint.ShapeLineStyle;
          }
        }
        touched = true;
      }

      if (fmt.fontName !== undefined && TEXT_TYPES.has(type)) {
        const f = s.textFrame.textRange.font;
        if (fmt.fontName) {
          f.name = fmt.fontName;
        }
        if (typeof fmt.fontSize === "number") {
          f.size = fmt.fontSize;
        }
        if (fmt.fontBold !== null && fmt.fontBold !== undefined) {
          f.bold = fmt.fontBold;
        }
        if (fmt.fontItalic !== null && fmt.fontItalic !== undefined) {
          f.italic = fmt.fontItalic;
        }
        if (fmt.fontUnderline) {
          f.underline = fmt.fontUnderline as unknown as PowerPoint.ShapeFontUnderlineStyle;
        }
        if (fmt.fontColor) {
          f.color = fmt.fontColor;
        }
        touched = true;
      }

      if (touched) {
        count++;
      }
    }
    await context.sync();
    return count;
  });
}
