/*
 * M2 — Dock.
 *
 * "Dock" pushes shapes flush against an edge. It differs from Align in two ways:
 *
 *  - Against the SLIDE, docking is flush *inside* the edge (dock-left → left = 0),
 *    which happens to coincide with align-to-slide for that edge.
 *  - Against the REFERENCE shape, docking is flush *outside* the edge: a shape
 *    docked left sits immediately to the LEFT of the reference, its right edge
 *    touching the reference's left edge. This is the "snap a label to the side
 *    of a box" operation, and it is NOT the same as aligning.
 *
 * Only the docking axis changes; the perpendicular position is preserved (so
 * several shapes docked to the same edge keep their spread on the other axis —
 * distribute afterwards if you want them evenly spaced). The reference shape
 * itself never moves.
 */

import { ShapeProps, SlideSize } from "./types";
import { bottom, right } from "./geometry";

export type DockEdge = "left" | "right" | "top" | "bottom";

/** Flush against the OUTSIDE of the reference's edge. */
function dockedOutside(shape: ShapeProps, edge: DockEdge, ref: ShapeProps): Partial<ShapeProps> {
  switch (edge) {
    case "left":
      return { left: ref.left - shape.width };
    case "right":
      return { left: right(ref) };
    case "top":
      return { top: ref.top - shape.height };
    case "bottom":
      return { top: bottom(ref) };
    default:
      return {};
  }
}

/** Flush against the INSIDE of the slide's edge. */
function dockedInside(shape: ShapeProps, edge: DockEdge, slide: SlideSize): Partial<ShapeProps> {
  switch (edge) {
    case "left":
      return { left: 0 };
    case "right":
      return { left: slide.width - shape.width };
    case "top":
      return { top: 0 };
    case "bottom":
      return { top: slide.height - shape.height };
    default:
      return {};
  }
}

/**
 * Docks every selected shape flush against the OUTSIDE of the reference shape's
 * edge. The reference shape is returned unchanged. Inputs are not mutated.
 */
export function dockToReference(
  shapes: ReadonlyArray<ShapeProps>,
  edge: DockEdge,
  reference: ShapeProps
): ShapeProps[] {
  return shapes.map((s) =>
    s.id === reference.id ? { ...s } : { ...s, ...dockedOutside(s, edge, reference) }
  );
}

/**
 * Docks every selected shape flush against the INSIDE of the given slide edge.
 * Inputs are not mutated.
 */
export function dockToSlide(
  shapes: ReadonlyArray<ShapeProps>,
  edge: DockEdge,
  slide: SlideSize
): ShapeProps[] {
  return shapes.map((s) => ({ ...s, ...dockedInside(s, edge, slide) }));
}
