/*
 * M6 typography half: scale line weight and font size on the live selection by
 * a factor. Kept in the office layer because it needs text-run access that the
 * pure engine doesn't model.
 *
 * Key behaviors:
 *  - Recurses into GROUPS to reach the text/lines of child shapes (a group has
 *    no text frame of its own, so without this its inner text never scales).
 *  - Only touches shapes whose type actually has a text frame / line format
 *    (loading those props on a group/picture/line would abort the whole batch).
 *  - "scale every run": uniform boxes scale in one write; mixed-size boxes are
 *    scanned character-by-character so each run scales and relative sizes survive.
 *  - Reports how many boxes changed / were unreadable, so the UI can say what
 *    happened instead of failing silently.
 */

/* global PowerPoint */

/** Longest mixed-size text box we'll character-scan for per-run scaling. */
const MIXED_SCAN_CAP = 2000;

/** Shape types that carry a text frame we can scale. */
const TEXT_TYPES = new Set(["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"]);
/** Shape types that carry a line format we can scale. */
const LINE_TYPES = new Set([
  "GeometricShape",
  "TextBox",
  "Placeholder",
  "Callout",
  "Freeform",
  "Line",
]);

export interface TypographyScale {
  lineWeight: boolean;
  fontSize: boolean;
}

export interface TypographyResult {
  changedLines: number;
  changedFonts: number;
  /** Text boxes that have text but no readable (numeric) font size. */
  unreadableFonts: number;
  /** Text boxes skipped because their mixed text exceeded the scan cap. */
  skippedLongMixed: string[];
}

interface FontEntry {
  shape: PowerPoint.Shape;
  label: string;
}

export async function scaleTypography(
  factor: number,
  opts: TypographyScale
): Promise<TypographyResult> {
  const result: TypographyResult = {
    changedLines: 0,
    changedFonts: 0,
    unreadableFonts: 0,
    skippedLongMixed: [],
  };
  if ((!opts.lineWeight && !opts.fontSize) || factor === 1) {
    return result;
  }

  await PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/name,items/type");
    await context.sync();

    // Flatten groups so we reach the actual text/line-bearing leaf shapes.
    const leaves = await collectLeafShapes(context, selected.items);

    const lineTargets: PowerPoint.Shape[] = [];
    const fontTargets: FontEntry[] = [];
    for (const shape of leaves) {
      const type = shape.type as unknown as string;
      const label = shape.name || shape.id;
      if (opts.lineWeight && LINE_TYPES.has(type)) {
        shape.lineFormat.load("weight");
        lineTargets.push(shape);
      }
      if (opts.fontSize && TEXT_TYPES.has(type)) {
        shape.textFrame.load("hasText");
        shape.textFrame.textRange.load("text");
        shape.textFrame.textRange.font.load("size");
        fontTargets.push({ shape, label });
      }
    }
    await context.sync();

    for (const shape of lineTargets) {
      const w = shape.lineFormat.weight;
      if (typeof w === "number" && w > 0) {
        shape.lineFormat.weight = w * factor;
        result.changedLines++;
      }
    }

    const mixed: FontEntry[] = [];
    for (const entry of fontTargets) {
      if (!entry.shape.textFrame.hasText) {
        continue;
      }
      const size = entry.shape.textFrame.textRange.font.size;
      if (typeof size === "number") {
        entry.shape.textFrame.textRange.font.size = size * factor; // uniform: one write
        result.changedFonts++;
      } else {
        mixed.push(entry); // mixed sizes (or unreadable): per-run pass
      }
    }
    if (mixed.length > 0) {
      await scaleMixedRuns(context, mixed, factor, result);
    }

    await context.sync();
  });

  return result;
}

/**
 * Expands any group shapes into their leaf descendants (depth-first), so we can
 * scale the text/lines inside groups. Loads child types level by level.
 */
async function collectLeafShapes(
  context: PowerPoint.RequestContext,
  shapes: PowerPoint.Shape[]
): Promise<PowerPoint.Shape[]> {
  const leaves: PowerPoint.Shape[] = [];
  let frontier = shapes;
  let depth = 0;
  while (frontier.length > 0 && depth++ < 10) {
    const groups: PowerPoint.Shape[] = [];
    for (const s of frontier) {
      if ((s.type as unknown as string) === "Group") {
        groups.push(s);
      } else {
        leaves.push(s);
      }
    }
    if (groups.length === 0) {
      break;
    }
    const childCollections = groups.map((g) => {
      const coll = g.group.shapes;
      coll.load("items/id,items/name,items/type");
      return coll;
    });
    // One sync per nesting level (bounded by `depth`) — unavoidable: we must
    // know a level's child types before deciding which to expand further.
    // eslint-disable-next-line office-addins/no-context-sync-in-loop
    await context.sync();
    frontier = [];
    for (const coll of childCollections) {
      frontier.push(...coll.items);
    }
  }
  return leaves;
}

/**
 * Scales each run of the given mixed-size text boxes. Reads every character's
 * size (one sync), groups consecutive equal sizes into runs, then queues a
 * size write per run. Caller does the final sync.
 */
async function scaleMixedRuns(
  context: PowerPoint.RequestContext,
  entries: FontEntry[],
  factor: number,
  result: TypographyResult
): Promise<void> {
  const scans = entries.map((entry) => {
    const range = entry.shape.textFrame.textRange;
    const text = range.text || "";
    const truncated = text.length > MIXED_SCAN_CAP;
    if (truncated) {
      result.skippedLongMixed.push(entry.label);
    }
    const len = truncated ? 0 : text.length;
    const chars = [];
    for (let i = 0; i < len; i++) {
      const sub = range.getSubstring(i, 1);
      sub.font.load("size");
      chars.push(sub);
    }
    return { entry, chars, len };
  });
  await context.sync();

  for (const { entry, chars, len } of scans) {
    if (len === 0) {
      continue;
    }
    const range = entry.shape.textFrame.textRange;
    let wroteAny = false;
    let runStart = 0;
    let runSize = chars[0].font.size;
    const flush = (endExclusive: number) => {
      if (typeof runSize === "number") {
        range.getSubstring(runStart, endExclusive - runStart).font.size = runSize * factor;
        wroteAny = true;
      }
    };
    for (let i = 1; i < len; i++) {
      const size = chars[i].font.size;
      if (size !== runSize) {
        flush(i);
        runStart = i;
        runSize = size;
      }
    }
    flush(len);
    if (wroteAny) {
      result.changedFonts++;
    } else {
      result.unreadableFonts++;
    }
  }
}
