/*
 * M11 — Text box fit (autoSizeSetting).
 *
 * Sets each selected shape's text-frame auto-size behavior:
 *   - shapeToText → shape grows/shrinks to fit its text (AutoSizeShapeToFitText)
 *   - textToShape → text shrinks to fit the shape (AutoSizeTextToFitShape)
 *   - none        → no auto-sizing (AutoSizeNone)
 *
 * autoSizeSetting is PowerPointApi 1.4 (stable, not preview — verified against
 * the type definitions), so it's available whenever the selection APIs are.
 * Shapes without a text frame (pictures, lines, groups) are skipped via
 * getTextFrameOrNullObject; on older builds we fall back to a type allowlist.
 */

/* global PowerPoint */

import { isSupported } from "./capabilities";

const TEXT_TYPES = new Set(["GeometricShape", "TextBox", "Placeholder", "Callout", "Freeform"]);

export type AutoSizeMode = "shapeToText" | "textToShape" | "none";

export async function setAutoSize(mode: AutoSizeMode): Promise<number> {
  const setting =
    mode === "shapeToText"
      ? PowerPoint.ShapeAutoSize.autoSizeShapeToFitText
      : mode === "textToShape"
        ? PowerPoint.ShapeAutoSize.autoSizeTextToFitShape
        : PowerPoint.ShapeAutoSize.autoSizeNone;

  const useNullObject = isSupported("textFrameNull");

  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type");
    await context.sync();

    const frames: PowerPoint.TextFrame[] = [];
    for (const shape of selected.items) {
      if (useNullObject) {
        const tf = shape.getTextFrameOrNullObject();
        tf.load("isNullObject");
        frames.push(tf);
      } else if (TEXT_TYPES.has(shape.type as unknown as string)) {
        frames.push(shape.textFrame);
      }
    }
    await context.sync();

    let count = 0;
    for (const tf of frames) {
      if (useNullObject && tf.isNullObject) {
        continue;
      }
      tf.autoSizeSetting = setting;
      count++;
    }
    await context.sync();
    return count;
  });
}

interface FitEntry {
  shape: PowerPoint.Shape;
  frame: PowerPoint.TextFrame;
  origW: number;
  origH: number;
  origWrap: boolean;
  size: number | null;
  factor: number;
}

/**
 * "Shrink text to fit" that ACTUALLY reduces font size (unlike the native
 * AutoSizeTextToFitShape, which only scales the display and leaves font.size
 * unchanged).
 *
 * Office.js can't measure rendered text, so we borrow PowerPoint's layout as an
 * oracle: temporarily switch the frame to AutoSizeShapeToFitText (with wrap on),
 * read the height it needs, then reduce the font by origHeight/neededHeight and
 * restore the box. One pass slightly under-shrinks (a smaller font wraps less),
 * so the text ends up fitting. Uniform text scales exactly; mixed-size text is
 * scaled per run to keep relative sizes.
 */
export async function shrinkFontToFit(): Promise<number> {
  const useNullObject = isSupported("textFrameNull");

  return PowerPoint.run(async (context) => {
    const selected = context.presentation.getSelectedShapes();
    selected.load("items/id,items/type,items/width,items/height");
    await context.sync();

    const entries: FitEntry[] = [];
    for (const shape of selected.items) {
      let frame: PowerPoint.TextFrame | null = null;
      if (useNullObject) {
        frame = shape.getTextFrameOrNullObject();
        frame.load("isNullObject,hasText,wordWrap");
      } else if (TEXT_TYPES.has(shape.type as unknown as string)) {
        frame = shape.textFrame;
        frame.load("hasText,wordWrap");
      }
      if (frame) {
        frame.textRange.font.load("size");
        entries.push({ shape, frame, origW: 0, origH: 0, origWrap: true, size: null, factor: 1 });
      }
    }
    await context.sync();

    const usable = entries.filter(
      (e) => !(useNullObject && e.frame.isNullObject) && e.frame.hasText
    );
    for (const e of usable) {
      e.origW = e.shape.width;
      e.origH = e.shape.height;
      e.origWrap = e.frame.wordWrap;
      e.size = e.frame.textRange.font.size;
      // Measure: grow shape to fit text (wrap on so it grows vertically).
      e.frame.wordWrap = true;
      e.frame.autoSizeSetting = PowerPoint.ShapeAutoSize.autoSizeShapeToFitText;
    }
    await context.sync();

    // Read the height each text now needs.
    for (const e of usable) {
      e.shape.load("height");
    }
    await context.sync();

    const mixed: FitEntry[] = [];
    let count = 0;
    for (const e of usable) {
      const neededH = e.shape.height;
      // Restore the box and turn auto-size off.
      e.frame.autoSizeSetting = PowerPoint.ShapeAutoSize.autoSizeNone;
      e.frame.wordWrap = e.origWrap;
      e.shape.height = e.origH;
      e.shape.width = e.origW;

      e.factor = e.origH > 0 && neededH > e.origH ? Math.min(1, (e.origH / neededH) * 0.95) : 1;
      if (e.factor < 1) {
        if (typeof e.size === "number") {
          e.frame.textRange.font.size = e.size * e.factor;
          count++;
        } else {
          mixed.push(e); // per-run pass below
        }
      }
    }
    await context.sync();

    if (mixed.length > 0) {
      count += await shrinkMixedRuns(context, mixed);
    }
    return count;
  });
}

/** Per-run font shrink for mixed-size boxes (each run scaled by the box's factor). */
async function shrinkMixedRuns(
  context: PowerPoint.RequestContext,
  entries: FitEntry[]
): Promise<number> {
  const CAP = 2000;
  const scans = entries.map((e) => {
    const range = e.frame.textRange;
    range.load("text");
    return { e, range, chars: [] as PowerPoint.TextRange[] };
  });
  await context.sync();

  for (const s of scans) {
    const len = Math.min((s.range.text || "").length, CAP);
    for (let i = 0; i < len; i++) {
      const sub = s.range.getSubstring(i, 1);
      sub.font.load("size");
      s.chars.push(sub);
    }
  }
  await context.sync();

  let count = 0;
  for (const s of scans) {
    const len = s.chars.length;
    if (len === 0) {
      continue;
    }
    let runStart = 0;
    let runSize = s.chars[0].font.size;
    let wrote = false;
    const flush = (end: number) => {
      if (typeof runSize === "number") {
        s.range.getSubstring(runStart, end - runStart).font.size = runSize * s.e.factor;
        wrote = true;
      }
    };
    for (let i = 1; i < len; i++) {
      const size = s.chars[i].font.size;
      if (size !== runSize) {
        flush(i);
        runStart = i;
        runSize = size;
      }
    }
    flush(len);
    if (wrote) {
      count++;
    }
  }
  await context.sync();
  return count;
}
